// ─── Behavioral Analysis: Extract the story from the simulation data ───
const sim = items[0].json.simulation;
const steps = sim.stepDetails || [];
const profile = sim.profile || 'unknown';

// Find the inflection point — first step where viability drops from initial
const initialViability = steps[0]?.viability || 'THRIVING';
let inflectionStep = null;
let inflectionFrom = initialViability;
let inflectionTo = null;
for (const step of steps) {
  if (step.viability !== initialViability && !inflectionStep) {
    inflectionStep = step.step;
    inflectionTo = step.viability;
    break;
  }
}

// Count rule frequency — which rules dominate the trajectory
const ruleCounts = {};
const ruleLabels = {};
for (const step of steps) {
  for (const rule of (step.rulesTriggered || [])) {
    ruleCounts[rule.ruleId] = (ruleCounts[rule.ruleId] || 0) + 1;
    ruleLabels[rule.ruleId] = rule.label;
  }
}

// Sort by frequency
const dominantRules = Object.entries(ruleCounts)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([id, count]) => ({ ruleId: id, label: ruleLabels[id], timesFired: count }));

// Find the first cascade — a step where 3+ rules fire simultaneously
let cascadeStep = null;
let cascadeRuleCount = 0;
for (const step of steps) {
  if ((step.rulesTriggered || []).length >= 3 && !cascadeStep) {
    cascadeStep = step.step;
    cascadeRuleCount = step.rulesTriggered.length;
    break;
  }
}

// Calculate degradation rates for key metrics
const initial = sim.initialState || {};
const final = sim.finalState || {};
const metrics = {};
for (const key of ['trust_score', 'revenue_margin', 'customer_satisfaction', 'abuse_rate', 'refund_rate', 'escalation_rate']) {
  if (initial[key] !== undefined && final[key] !== undefined) {
    const start = Number(initial[key]);
    const end = Number(final[key]);
    const change = end - start;
    const pctChange = start !== 0 ? Math.round((change / start) * 100) : 0;
    metrics[key] = {
      start: Math.round(start * 10) / 10,
      end: Math.round(end * 10) / 10,
      change: Math.round(change * 10) / 10,
      pctChange,
      direction: change > 0 ? 'increased' : change < 0 ? 'decreased' : 'unchanged'
    };
  }
}

// Identify root cause — the earliest-firing degradation/structural rule
let rootCause = null;
for (const step of steps) {
  for (const rule of (step.rulesTriggered || [])) {
    const dominant = dominantRules.find(d => d.ruleId === rule.ruleId);
    if (dominant && dominant.timesFired >= 3) {
      rootCause = { ruleId: rule.ruleId, label: rule.label, firstStep: step.step, totalFires: dominant.timesFired };
      break;
    }
  }
  if (rootCause) break;
}

return [{
  json: {
    profile,
    finalViability: sim.finalViability,
    collapsed: sim.collapsed || false,
    collapseStep: sim.collapseStep || null,
    totalSteps: steps.length,
    inflection: inflectionStep ? {
      step: inflectionStep,
      from: inflectionFrom,
      to: inflectionTo
    } : null,
    cascade: cascadeStep ? {
      step: cascadeStep,
      simultaneousRules: cascadeRuleCount
    } : null,
    dominantRules,
    rootCause,
    metrics,
    trajectory: steps.map(s => ({
      step: s.step,
      viability: s.viability,
      rulesFired: s.rulesFired
    }))
  }
}];

