// ─── Merge all 3 profiles and generate the behavioral comparison ───

// Collect analyses from the 3 input connections
const best = items[0]?.json || {};
const expected = items[1]?.json || {};
const worst = items[2]?.json || {};

const profiles = { best_case: best, expected, worst_case: worst };

// ─── Decision Logic ───
const viabilities = [best.finalViability, expected.finalViability, worst.finalViability];
const anyCritical = viabilities.includes('CRITICAL') || viabilities.includes('MODEL_COLLAPSES');
const anyCollapsed = best.collapsed || expected.collapsed || worst.collapsed;
const allHealthy = viabilities.every(v => v === 'THRIVING' || v === 'STABLE');
const expectedOk = expected.finalViability === 'THRIVING' || expected.finalViability === 'STABLE';

let decision, recommendation;
if (allHealthy) {
  decision = 'APPROVE';
  recommendation = 'All scenarios remain healthy through 10 steps. Safe to enable auto-refunds.';
} else if (expectedOk && !anyCollapsed) {
  decision = 'APPROVE_WITH_GUARDRAILS';
  recommendation = 'Expected case is stable, but worst case shows degradation. Enable with monitoring and abuse detection guardrails.';
} else if (anyCritical || anyCollapsed) {
  decision = 'BLOCK';
  recommendation = 'System reaches CRITICAL or collapses under realistic conditions. Do NOT enable auto-refunds without fundamental changes.';
} else {
  decision = 'REVIEW';
  recommendation = 'Mixed results — requires human review of the behavioral trajectories before proceeding.';
}

// ─── Find the most dangerous rule across all profiles ───
const allRules = {};
for (const [name, profile] of Object.entries(profiles)) {
  for (const rule of (profile.dominantRules || [])) {
    const key = rule.ruleId;
    if (!allRules[key]) allRules[key] = { ruleId: key, label: rule.label, totalFires: 0, profiles: [] };
    allRules[key].totalFires += rule.timesFired;
    allRules[key].profiles.push(name);
  }
}
const topThreats = Object.values(allRules).sort((a, b) => b.totalFires - a.totalFires).slice(0, 3);

// ─── Build the report ───
const lines = [];
lines.push('===== BEHAVIORAL SIMULATION REPORT =====');
lines.push('');
lines.push('Policy: Enable AI auto-refunds under $100');
lines.push('Simulation: 10 steps across 3 assumption profiles');
lines.push('');
lines.push('--- OUTCOMES ---');
for (const [name, profile] of Object.entries(profiles)) {
  const label = name.replace('_', ' ').toUpperCase();
  const v = profile.finalViability || 'UNKNOWN';
  const collapsed = profile.collapsed ? ' [COLLAPSED]' : '';
  lines.push(`  ${label}: ${v}${collapsed}`);
  if (profile.inflection) {
    lines.push(`    Inflection: Step ${profile.inflection.step} (${profile.inflection.from} -> ${profile.inflection.to})`);
  }
  if (profile.cascade) {
    lines.push(`    First cascade: Step ${profile.cascade.step} (${profile.cascade.simultaneousRules} rules firing simultaneously)`);
  }
  if (profile.metrics?.trust_score) {
    const t = profile.metrics.trust_score;
    lines.push(`    Trust: ${t.start} -> ${t.end} (${t.pctChange > 0 ? '+' : ''}${t.pctChange}%)`);
  }
  if (profile.metrics?.revenue_margin) {
    const r = profile.metrics.revenue_margin;
    lines.push(`    Revenue margin: ${r.start} -> ${r.end} (${r.pctChange > 0 ? '+' : ''}${r.pctChange}%)`);
  }
  if (profile.metrics?.abuse_rate) {
    const a = profile.metrics.abuse_rate;
    lines.push(`    Abuse rate: ${a.start} -> ${a.end} (${a.pctChange > 0 ? '+' : ''}${a.pctChange}%)`);
  }
  lines.push('');
}

lines.push('--- ROOT CAUSE ANALYSIS ---');
for (const threat of topThreats) {
  lines.push(`  ${threat.label} (${threat.ruleId})`);
  lines.push(`    Fired ${threat.totalFires}x across profiles: ${threat.profiles.join(', ')}`);
}
lines.push('');

if (worst.rootCause) {
  lines.push('--- WORST CASE ROOT CAUSE ---');
  lines.push(`  Rule: ${worst.rootCause.label}`);
  lines.push(`  First fires at: Step ${worst.rootCause.firstStep}`);
  lines.push(`  Total fires: ${worst.rootCause.totalFires}x in 10 steps`);
  lines.push('');
}

lines.push('--- DECISION ---');
lines.push(`  ${decision}`);
lines.push(`  ${recommendation}`);

const report = lines.join('\n');

return [{
  json: {
    decision,
    recommendation,
    report,
    profiles: {
      best_case: { viability: best.finalViability, collapsed: best.collapsed, inflection: best.inflection, metrics: best.metrics },
      expected: { viability: expected.finalViability, collapsed: expected.collapsed, inflection: expected.inflection, metrics: expected.metrics },
      worst_case: { viability: worst.finalViability, collapsed: worst.collapsed, inflection: worst.inflection, metrics: worst.metrics }
    },
    topThreats,
    worstCaseRootCause: worst.rootCause || null
  }
}];
